const escapeText = (value = '') => String(value).replace(/[&<>"]/g, c => ({ '&':'&amp;', '<':'&lt;', '>':'&gt;', '"':'&quot;' }[c]))
const optionHtml = (list, selected) => list.map(item => `<option value="${escapeText(item)}" ${item === selected ? 'selected' : ''}>${escapeText(item)}</option>`).join('')
const stored = (key, fallback) => JSON.parse(localStorage.getItem(key) || JSON.stringify(fallback))
const save = (key, value) => localStorage.setItem(key, JSON.stringify(value))
const questionBank = () => stored('mezzo_question_bank', seedQuestions)
const setQuestionBank = list => save('mezzo_question_bank', list)
const generationSummary = () => stored('mezzo_generation_summary', { totalGenerated: 0, batches: [] })
const saveGenerationSummary = summary => save('mezzo_generation_summary', summary)
const topicOptionsFor = level => topicsByLevel[level] || basicTopics
const isAdmin = () => state.user?.role === 'admin'
const ageFromDob = dob => { if (!dob) return ''; const today = new Date(); const born = new Date(dob); let age = today.getFullYear() - born.getFullYear(); const m = today.getMonth() - born.getMonth(); if (m < 0 || (m === 0 && today.getDate() < born.getDate())) age--; return Number.isFinite(age) ? age : '' }

function selectedTopicArea(level, topic) { return inferTopicArea(topic || topicOptionsFor(level)[0] || 'General Practice') }
function topicAreaBadge(level, topic) { const area = selectedTopicArea(level, topic); return `<div class="smart-topic-note"><strong>Auto-matched topic area:</strong> ${escapeText(area)}. This is locked to the selected topic so generated questions cannot mismatch.</div>` }
function questionKey(q) { return String(q.id || `${q.class_level}|${q.curriculum}|${q.topic}|${q.question_text}|${q.numeric_answer || ''}`) }
function shuffle(list) { return [...list].sort(() => Math.random() - 0.5) }
function pickFreshQuestions(pool, count, key) {
  const recentKey = `mezzo_recent_${key}`
  const recent = stored(recentKey, [])
  let candidates = pool.filter(q => !recent.includes(questionKey(q)))
  if (candidates.length < count) candidates = pool
  const selected = shuffle(candidates).slice(0, count)
  save(recentKey, [...selected.map(questionKey), ...recent].slice(0, count * 6))
  return selected
}

