function smartLiveHtml(current) { if (!current) return `<section class="empty-practice light-card"><h2>No question loaded</h2><p>Start again from setup.</p></section>`; const s = state.smart; return `<section class="smart-live-board"><aside class="smart-score-card student-a"><div class="contest-label">Student A</div><h2>${escapeText(s.a.name || 'Student A')}</h2><p>${escapeText(s.a.school || 'School')} • ${escapeText(s.a.classLevel)}</p><strong>${s.a.score}</strong><small>Last speed: ${s.a.lastTime ? `${s.a.lastTime}s` : '—'}</small></aside><main class="smart-question-zone light-card"><div class="smart-meta"><span>Round ${s.round + 1}</span><span>${escapeText(s.topicArea)}</span><span>${escapeText(s.message)}</span></div><h1>${escapeText(current.question_text)}</h1><div class="smart-answer-status">${escapeText(s.topic)} • correct answer hidden until awarded.</div></main><aside class="smart-score-card student-b"><div class="contest-label">Student B</div><h2>${escapeText(s.b.name || 'Student B')}</h2><p>${escapeText(s.b.school || 'School')} • ${escapeText(s.b.classLevel)}</p><strong>${s.b.score}</strong><small>Last speed: ${s.b.lastTime ? `${s.b.lastTime}s` : '—'}</small></aside>${smartKeypad('a', s.a.answer, 'Student A Keypad')}<section class="smart-center-status glass-card"><div>${s.phase === 'countdown' ? `<strong class="giant-count">${s.countdown}</strong><span>Get ready...</span>` : `<strong>FASTEST CORRECT ANSWER WINS</strong><span>New questions continue until time ends</span>`}</div><button class="btn btn-danger" id="endSmartContest">End Contest</button></section>${smartKeypad('b', s.b.answer, 'Student B Keypad')}</section>` }
