function smartBoardResultHtml() { const s = state.smart; const winner = s.winner || s.a; const runner = s.runnerUp || s.b; return `<section class="smart-result-wrap"><section class="winner-card light-card confetti-burst"><div class="trophy-anim">🏆</div><h1>Congratulations, ${escapeText(winner.name || 'Winner')}!</h1><p>${escapeText(winner.school || 'School')} • ${escapeText(winner.classLevel || s.classLevel)}</p><strong>${winner.score} points</strong><div class="clap-text">👏 👏 👏</div><button class="btn btn-gold" id="playClap">Play Clapping Sound</button><button class="btn btn-primary" id="resetSmartContest">New Smart Board Contest</button></section><section class="runner-card glass-card"><h2>Second Place: ${escapeText(runner.name || 'Runner Up')}</h2><p>${escapeText(runner.school || 'School')} • ${runner.score} points</p><div class="ai-message">AI Motivation: You showed courage and speed today. Keep practising ${escapeText(s.topic)}; today’s second place can become tomorrow’s trophy.</div></section><section class="smart-leader-preview glass-card"><h2>Weekly, Monthly and Yearly Leaderboards</h2>${leaderboardScopeHtml('weekly')}${leaderboardScopeHtml('monthly')}${leaderboardScopeHtml('yearly')}</section></section>` }
