  const list = questionBank(); const editing = Number.isInteger(state.editingIndex) ? list[state.editingIndex] : null; const adminLevel = editing?.class_level || 'Grade 4'; const adminTopic = editing?.topic || 'Multiplication by 4 (2 Digits)'; const matchedArea = selectedTopicArea(adminLevel, adminTopic)
