function rawQuestion({ class_level, curriculum, topic, topic_area, topic_sublevel, a, b, symbol, answer }) {
  return { class_level, curriculum, topic, topic_area, topic_sublevel, difficulty: 1, question_text: symbol === '²' ? `${a}²` : `${a} ${symbol} ${b}`, numeric_answer: answer, option_a: String(answer - 1), option_b: String(answer), option_c: String(answer + 1), option_d: String(answer + 2), correct_answer: 'B', explanation: `The answer is ${answer}.`, ai_generated: true, is_active: true }
}
function wordQuestion({ class_level, curriculum, topic, topic_area, topic_sublevel, a, b, symbol, answer }) {
  const templates = {
    Addition: `A school library had ${a} maths books. The headteacher donated ${b} more. How many maths books are there now?`,
    'Addition & Subtraction': symbol === '+' ? `A class had ${a} exercise books and received ${b} more. How many books do they have now?` : `A school bought ${a} pencils and gave ${b} to pupils. How many pencils were left?`,
    Subtraction: `There were ${a} chairs in the hall. Pupils moved ${b} chairs to another classroom. How many chairs remained?`,
    Multiplication: `There are ${a} groups of students with ${b} students in each group. How many students are there altogether?`,
    Division: `A teacher shares ${a} pencils equally among ${b} pupils. How many pencils will each pupil receive?`,
    Divisibility: `A teacher wants to share ${a} counters equally among ${b} learners. How many counters will each learner get?`,
    Squaring: `A square garden has side length ${a} metres. What is its area in square metres?`,
    Percentages: `A student scored ${a}% in a quiz of ${b} questions. Use the given values to choose the closest answer.`
  }
  return { class_level, curriculum, topic, topic_area, topic_sublevel, difficulty: 2, question_text: templates[topic_area] || `A maths contest question uses the numbers ${a} and ${b}. Calculate ${symbol === '²' ? `${a}²` : `${a} ${symbol} ${b}`}.`, numeric_answer: answer, option_a: String(answer - 1), option_b: String(answer), option_c: String(answer + 1), option_d: String(answer + 2), correct_answer: 'B', explanation: `Work through the word problem carefully. The answer is ${answer}.`, ai_generated: true, is_active: true }
}
function makeGeneratedQuestions({ count = 15, class_level = 'Grade 4', curriculum = 'GES', topic = 'Multiplication by 4 (2 Digits)', topic_sublevel = 'Class topic' }) {
  const topic_area = inferTopicArea(topic)
  const rand = (min, max) => Math.floor(Math.random() * (max - min + 1)) + min
  return Array.from({ length: Number(count) }, (_, i) => {
    let a = rand(2,9), b = rand(2,9), symbol = '×', answer = a * b
    if (topic_sublevel === '2 digit × 1 digit') { a = rand(12,99); b = rand(2,9); answer = a * b }
    if (topic_sublevel === '2 digit × 2 digit') { a = rand(12,99); b = rand(11,99); answer = a * b }
    if (topic_area === 'Addition') { a = rand(10,99); b = rand(10,99); symbol = '+'; answer = a + b }
    if (topic_area === 'Addition & Subtraction') { a = rand(20,99); b = rand(10,59); symbol = Math.random() > 0.5 ? '+' : '−'; answer = symbol === '+' ? a + b : a - b }
    if (topic_area === 'Subtraction') { a = rand(40,150); b = rand(10,39); symbol = '−'; answer = a - b }
    if (topic_area === 'Division' || topic_area === 'Divisibility') { b = rand(2,12); answer = rand(2,25); a = answer * b; symbol = '÷' }
    if (topic_area === 'Squaring') { a = rand(2,25); b = 2; symbol = '²'; answer = a * a }
    const payload = { class_level, curriculum, topic, topic_area, topic_sublevel, a, b, symbol, answer }
    const shouldBeWord = topic_area === 'Word Problems' || i >= Math.ceil(Number(count) * 0.35) && i % 2 === 0
    return shouldBeWord ? wordQuestion(payload) : rawQuestion(payload)
  })
}
function prepareQuestionForDb(q) { const area = inferTopicArea(q.topic); return { class_level: q.class_level, curriculum: q.curriculum, topic: q.topic, topic_area: area, topic_sublevel: q.topic_sublevel || 'Class topic', difficulty: Number(q.difficulty || 1), question_text: q.question_text, numeric_answer: q.numeric_answer === '' || q.numeric_answer === undefined || q.numeric_answer === null ? null : Number(q.numeric_answer), option_a: q.option_a || String(Number(q.numeric_answer || 0) - 1), option_b: q.option_b || String(q.numeric_answer || ''), option_c: q.option_c || String(Number(q.numeric_answer || 0) + 1), option_d: q.option_d || String(Number(q.numeric_answer || 0) + 2), correct_answer: q.correct_answer || 'B', explanation: q.explanation || '', ai_generated: Boolean(q.ai_generated), is_active: true } }
async function loadQuestionSet({ classLevel, curriculum, topic, count = 15, key = 'practice', numericOnly = false }) {
  const topicArea = inferTopicArea(topic)
  let pool = []
  if (supabase) {
    let query = supabase.from('question_bank').select('*').eq('class_level', classLevel).eq('curriculum', curriculum).eq('topic', topic).eq('is_active', true).limit(300)
    if (numericOnly) query = query.not('numeric_answer', 'is', null)
    const { data } = await query
    if (data?.length) pool = data.filter(q => !q.topic_area || q.topic_area === topicArea || inferTopicArea(q.topic) === topicArea)
  }
  if (!pool.length) pool = questionBank().filter(q => q.class_level === classLevel && q.curriculum === curriculum && q.topic === topic && (!numericOnly || q.numeric_answer) && (!q.topic_area || q.topic_area === topicArea || inferTopicArea(q.topic) === topicArea))
  if (!pool.length) pool = makeGeneratedQuestions({ count: Math.max(60, count), class_level: classLevel, curriculum, topic, topic_sublevel: 'Class topic' })
  return pickFreshQuestions(pool, count, `${key}_${classLevel}_${curriculum}_${topic}`)
}
async function loadQuestionsFromDatabase(filters = {}) { if (!supabase) { state.message = 'Supabase is not configured yet. Add VITE_SUPABASE_URL and VITE_SUPABASE_ANON_KEY in Vercel.'; return false } let query = supabase.from('question_bank').select('*').eq('is_active', true).order('created_at', { ascending: false }).limit(1000); if (filters.class_level) query = query.eq('class_level', filters.class_level); if (filters.curriculum) query = query.eq('curriculum', filters.curriculum); if (filters.topic) query = query.eq('topic', filters.topic); if (filters.numericOnly) query = query.not('numeric_answer', 'is', null); const { data, error } = await query; if (error) { state.message = `Database load failed: ${error.message}`; return false } if (data?.length) { setQuestionBank(data); state.adminPage = 1; state.lastDbLoad = `${data.length} questions loaded at ${new Date().toLocaleTimeString()}`; state.message = `Loaded ${data.length} questions from Supabase database.`; return true } state.lastDbLoad = `No database questions found at ${new Date().toLocaleTimeString()}`; state.message = 'No matching questions found in Supabase yet.'; return false }
async function saveGeneratedQuestionsToDatabase(questions, batch) { if (!supabase) { state.message = `${questions.length} questions generated locally. Supabase is not configured, so they were not saved to the cloud database.`; return false } const payload = questions.map(prepareQuestionForDb); const { error } = await supabase.from('question_bank').insert(payload); if (error) { state.message = `${questions.length} questions generated locally, but database save failed: ${error.message}`; return false } await supabase.from('ai_question_generations').insert({ class_level: batch.class_level, curriculum: batch.curriculum, topic: batch.topic, topic_area: inferTopicArea(batch.topic), topic_sublevel: batch.topic_sublevel || 'Class topic', question_count: questions.length, difficulty: 1, prompt: `Generated ${questions.length} mixed ${batch.topic} questions for ${batch.class_level} ${batch.curriculum}`, status: 'completed' }).then(() => {}).catch(() => {}); state.message = `${questions.length} mixed direct/word questions generated and saved in Supabase question_bank.`; return true }
async function syncLocalQuestionsToDatabase() { const list = questionBank().filter(q => !q.id); if (!list.length) { state.message = 'All visible questions already appear to be database records.'; render(); return } const ok = await saveGeneratedQuestionsToDatabase(list, { class_level: 'Mixed', curriculum: 'GES', topic: 'Bulk Sync', topic_sublevel: 'Mixed' }); if (ok) await loadQuestionsFromDatabase(); render() }

async function startSmartContest() { clearInterval(countdownTimer); clearInterval(contestTimer); const duration = Number(document.getElementById('smartDuration')?.value || 60); const classLevel = document.getElementById('smartClass')?.value || 'Grade 4'; const curriculum = document.getElementById('smartCurriculum')?.value || 'GES'; const topic = document.getElementById('smartTopic')?.value || 'Multiplication by 4 (2 Digits)'; const topicArea = inferTopicArea(topic); const a = { name: document.getElementById('aName')?.value || 'Student A', school: document.getElementById('aSchool')?.value || 'School A', classLevel: document.getElementById('aClass')?.value || classLevel, score: 0, answer: '', lastTime: 0 }; const b = { name: document.getElementById('bName')?.value || 'Student B', school: document.getElementById('bSchool')?.value || 'School B', classLevel: document.getElementById('bClass')?.value || classLevel, score: 0, answer: '', lastTime: 0 }; let questions = await loadQuestionSet({ classLevel, curriculum, topic, count: 200, key: 'smartboard', numericOnly: true }); while (questions.length < 200) questions = [...questions, ...makeGeneratedQuestions({ count: 50, class_level: classLevel, curriculum, topic, topic_sublevel: 'Class topic' })]; state.smart = { ...defaultSmartState(), phase: 'countdown', countdown: 5, duration, remaining: duration, topic, topicArea, classLevel, curriculum, questions: shuffle(questions), a, b, message: `Loaded ${questions.length} reshuffled ${topicArea} questions. Get ready!` }; render(); countdownTimer = setInterval(() => { state.smart.countdown -= 1; if (state.smart.countdown <= 0) beginSmartLive(); else render() }, 1000) }
function beginSmartLive() { clearInterval(countdownTimer); state.smart.phase = 'live'; state.smart.round = 0; state.smart.roundStartedAt = Date.now(); state.smart.message = 'Answer now!'; render(); contestTimer = setInterval(() => { state.smart.remaining -= 1; if (state.smart.remaining <= 0) endSmartContest(); else render() }, 1000) }
function smartSubmit(side) { if (state.smart.phase !== 'live' || state.smart.roundWinner) return; const q = state.smart.questions[state.smart.round]; const player = state.smart[side]; const seconds = Number(((Date.now() - state.smart.roundStartedAt) / 1000).toFixed(2)); player.lastTime = seconds; if (Number(q.numeric_answer) === Number(player.answer)) { const points = 10 + Math.max(1, Math.ceil(10 - seconds)); player.score += points; state.smart.roundWinner = side; state.smart.message = `${player.name} answered fastest! +${points} points`; render(); setTimeout(nextSmartQuestion, 700) } else { state.smart.message = `${player.name} submitted ${player.answer || 'blank'} — not correct.`; player.answer = ''; render() } }
function nextSmartQuestion() { if (state.smart.phase !== 'live') return; if (state.smart.remaining <= 0) { endSmartContest(); return } state.smart.round += 1; if (state.smart.round >= state.smart.questions.length) state.smart.questions.push(...makeGeneratedQuestions({ count: 50, class_level: state.smart.classLevel, curriculum: state.smart.curriculum, topic: state.smart.topic, topic_sublevel: 'Class topic' })); state.smart.a.answer = ''; state.smart.b.answer = ''; state.smart.roundWinner = ''; state.smart.roundStartedAt = Date.now(); state.smart.message = 'Next question. Fastest correct answer wins!'; render() }
function endSmartContest() { clearInterval(countdownTimer); clearInterval(contestTimer); const a = state.smart.a, b = state.smart.b; const winner = a.score >= b.score ? a : b; const runnerUp = a.score >= b.score ? b : a; state.smart.phase = 'result'; state.smart.winner = winner; state.smart.runnerUp = runnerUp; recordSmartWinner(winner); playClap(); render() }
function resetSmartContest() { clearInterval(countdownTimer); clearInterval(contestTimer); state.smart = defaultSmartState(); render() }
function recordSmartWinner(winner) { const boards = stored('mezzo_smart_leaderboards', { weekly: [], monthly: [], yearly: [] }); const row = { name: winner.name, school: winner.school, classLevel: winner.classLevel, score: winner.score, topic: state.smart.topic, topicArea: state.smart.topicArea, date: new Date().toISOString() }; for (const scope of ['weekly','monthly','yearly']) boards[scope] = [row, ...(boards[scope] || [])].sort((x,y) => y.score - x.score).slice(0,50); save('mezzo_smart_leaderboards', boards) }
function inferTopicArea(topic) { const t = String(topic || '').toLowerCase(); if (t.includes('addition') && t.includes('subtraction')) return 'Addition & Subtraction'; if (t.includes('word problem')) return 'Word Problems'; if (t.includes('fraction')) return 'Fractions'; if (t.includes('percent')) return 'Percentages'; if (t.includes('divisibility')) return 'Divisibility'; if (t.includes('division') || t.includes('sharing')) return 'Division'; if (t.includes('subtraction') || t.includes('subtract') || t.includes('fast track')) return 'Subtraction'; if (t.includes('add') || t.includes('consecutive')) return 'Addition'; if (t.includes('squar') || t.includes('square')) return 'Squaring'; if (t.includes('worksheet') || t.includes('trials') || t.includes('summary')) return 'Worksheet'; if (t.includes('algebra')) return 'Algebra'; if (t.includes('geometry')) return 'Geometry'; if (t.includes('statistic')) return 'Statistics'; if (t.includes('multip') || t.includes('mult') || t.includes('mul ') || t.includes('lattice') || t.includes('graphical') || t.includes('doubling') || t.includes('mezzoscopic')) return 'Multiplication'; return 'General Practice' }
function playClap() { try { const ctx = new (window.AudioContext || window.webkitAudioContext)(); for (let i = 0; i < 5; i++) { const size = ctx.sampleRate * 0.08; const buffer = ctx.createBuffer(1, size, ctx.sampleRate); const data = buffer.getChannelData(0); for (let j = 0; j < size; j++) data[j] = (Math.random() * 2 - 1) * Math.pow(1 - j / size, 2); const source = ctx.createBufferSource(); source.buffer = buffer; const gain = ctx.createGain(); gain.gain.value = 0.35; source.connect(gain).connect(ctx.destination); source.start(ctx.currentTime + i * 0.16) } } catch {} }

async function startSolo(mode = 'Solo Practice') { const classLevel = document.getElementById('soloClass')?.value || state.solo.classLevel || state.user?.class_level || 'Grade 8'; const curriculum = document.getElementById('soloCurriculum')?.value || state.solo.curriculum || state.user?.curriculum || 'GES'; let topic = document.getElementById('soloTopic')?.value || state.solo.topic || topicOptionsFor(classLevel)[0]; if (mode === 'Daily Practice') topic = shuffle(topicOptionsFor(classLevel))[0] || topic; const questions = await loadQuestionSet({ classLevel, curriculum, topic, count: 15, key: mode.toLowerCase().replaceAll(' ', '_') }); state.view = 'solo'; state.solo = { ...state.solo, mode, classLevel, curriculum, topic, topicArea: inferTopicArea(topic), questions, index: 0, score: 0, selected: '', finished: false, started: true }; state.message = `${mode} loaded ${questions.length} reshuffled database questions for ${topic}.`; render() }
async function startBattle(opponent = null) { const classLevel = document.getElementById('battleClass')?.value || state.battle.classLevel; const curriculum = document.getElementById('battleCurriculum')?.value || state.battle.curriculum; const topic = document.getElementById('battleTopic')?.value || state.battle.topic; const selectedOpponent = opponent || document.getElementById('battleOpponent')?.value || state.battle.opponent; const questions = await loadQuestionSet({ classLevel, curriculum, topic, count: 15, key: selectedOpponent === 'Bot' ? 'bot_battle' : 'online_battle' }); state.view = 'battle'; state.battle = { ...state.battle, mode: selectedOpponent === 'Bot' ? 'Compete With Bot' : 'Online 1 vs 1', classLevel, curriculum, topic, topicArea: inferTopicArea(topic), opponent: selectedOpponent, questions, index: 0, score: 0, opponentScore: 0, selected: '', finished: false, started: true }; state.message = `${state.battle.mode} loaded ${questions.length} reshuffled database questions for ${topic}.`; render() }
function nextSoloQuestion() { if (state.solo.index >= state.solo.questions.length - 1) { state.solo.finished = true; state.solo.started = false } else { state.solo.index += 1; state.solo.selected = '' } render() }
function nextBattleQuestion() { if (state.battle.index >= state.battle.questions.length - 1) { state.battle.finished = true; state.battle.started = false } else { state.battle.index += 1; state.battle.selected = ''; if (state.battle.opponent === 'Bot' && Math.random() > 0.47) state.battle.opponentScore += 1 } render() }
async function aiGenerate(form) { const f = Object.fromEntries(new FormData(form).entries()); f.topic_area = inferTopicArea(f.topic); let generated = null; if (supabase) { try { const { data } = await supabase.functions.invoke('generate-questions', { body: f }); if (data?.questions?.length) generated = data.questions } catch { generated = null } } generated ||= makeGeneratedQuestions(f); const prepared = generated.map(q => ({ ...q, topic_area: inferTopicArea(q.topic || f.topic), ai_generated: true, is_active: true })); setQuestionBank([...prepared, ...questionBank()]); const summary = generationSummary(); summary.totalGenerated += prepared.length; summary.batches.unshift({ count: prepared.length, class_level: f.class_level, curriculum: f.curriculum, topic: f.topic, topic_area: f.topic_area, topic_sublevel: f.topic_sublevel, created_at: new Date().toLocaleString() }); saveGenerationSummary(summary); state.adminPage = 1; const saved = await saveGeneratedQuestionsToDatabase(prepared, f); if (saved) await loadQuestionsFromDatabase(); render() }
async function saveQuestion(form) { const f = Object.fromEntries(new FormData(form).entries()); const list = questionBank(); const idx = f.editing_index === '' ? -1 : Number(f.editing_index); const existing = idx >= 0 ? list[idx] : null; const item = { ...existing, class_level: f.class_level, curriculum: f.curriculum, topic: f.topic, topic_area: inferTopicArea(f.topic), numeric_answer: f.numeric_answer ? Number(f.numeric_answer) : null, question_text: f.question_text, option_a: f.option_a, option_b: f.option_b, option_c: f.option_c, option_d: f.option_d, correct_answer: f.correct_answer, explanation: f.explanation, difficulty: existing?.difficulty || 1, is_active: true }; if (supabase) { const dbItem = prepareQuestionForDb(item); const { data, error } = item.id ? await supabase.from('question_bank').update(dbItem).eq('id', item.id).select().single() : await supabase.from('question_bank').insert(dbItem).select().single(); if (error) state.message = `Database save failed: ${error.message}`; else { if (idx >= 0) list[idx] = data; else list.unshift(data); state.message = item.id ? 'Question updated in Supabase database.' : 'Question saved in Supabase database.' } } else { if (idx >= 0) list[idx] = item; else list.unshift(item); state.message = idx >= 0 ? 'Question updated locally. Supabase is not configured.' : 'Question saved locally. Supabase is not configured.' } setQuestionBank(list); state.editingIndex = null; render() }
async function signup(form) { const raw = Object.fromEntries(new FormData(form).entries()); const profile = { ...raw, age: ageFromDob(raw.date_of_birth) }; delete profile.password; save('mezzo_profile', profile); state.user = profile; state.message = 'Demo account created.'; state.view = 'dashboard'; render() }
async function login(form) { const f = Object.fromEntries(new FormData(form).entries()); const local = stored('mezzo_profile', {}) || {}; local.email = f.email; local.role = f.role; save('mezzo_profile', local); state.user = local; state.message = 'Demo login successful.'; state.view = f.role === 'admin' ? 'admin' : 'dashboard'; if (f.role === 'admin') await loadQuestionsFromDatabase(); render() }

document.addEventListener('click', async e => {
  const daily = e.target.closest('[data-start-daily]'); if (daily) { state.view = 'solo'; render(); await startSolo('Daily Practice'); return }
  const bot = e.target.closest('[data-start-bot]'); if (bot) { state.view = 'battle'; render(); await startBattle('Bot'); return }
  const target = e.target.closest('[data-target]'); if (target) { clearInterval(countdownTimer); clearInterval(contestTimer); state.view = target.dataset.target; state.message = ''; state.editingIndex = null; if (state.view === 'admin') await loadQuestionsFromDatabase(); render(); return }
  const mode = e.target.closest('[data-auth-mode]'); if (mode) { state.authMode = mode.dataset.authMode; render(); return }
  const adminPage = e.target.closest('[data-admin-page]'); if (adminPage) { state.adminPage = Number(adminPage.dataset.adminPage); render(); return }
  const edit = e.target.closest('[data-edit-question]'); if (edit) { state.editingIndex = Number(edit.dataset.editQuestion); render(); return }
  const del = e.target.closest('[data-delete-question]'); if (del) { const list = questionBank(); const idx = Number(del.dataset.deleteQuestion); const q = list[idx]; if (supabase && q?.id) await supabase.from('question_bank').update({ is_active: false }).eq('id', q.id); list.splice(idx, 1); setQuestionBank(list); state.message = 'Question deleted.'; render(); return }
  const key = e.target.closest('[data-key]'); if (key && state.smart.phase === 'live') { const p = state.smart[key.dataset.pad]; p.answer = key.dataset.key === '⌫' ? p.answer.slice(0,-1) : `${p.answer}${key.dataset.key}`; render(); return }
  const smartSubmitBtn = e.target.closest('[data-submit-smart]'); if (smartSubmitBtn) { smartSubmit(smartSubmitBtn.dataset.submitSmart); return }
  const soloAnswer = e.target.closest('[data-solo-answer]'); if (soloAnswer && !state.solo.selected) { const q = state.solo.questions[state.solo.index]; state.solo.selected = soloAnswer.dataset.soloAnswer; if (state.solo.selected === q.correct_answer) state.solo.score += 1; render(); return }
  const battleAnswer = e.target.closest('[data-battle-answer]'); if (battleAnswer && !state.battle.selected) { const q = state.battle.questions[state.battle.index]; state.battle.selected = battleAnswer.dataset.battleAnswer; if (state.battle.selected === q.correct_answer) state.battle.score += 1; if (state.battle.opponent !== 'Bot' && Math.random() > 0.52) state.battle.opponentScore += 1; render(); return }
  if (e.target.closest('#nextSolo')) { nextSoloQuestion(); return }
  if (e.target.closest('#nextBattle')) { nextBattleQuestion(); return }
  if (e.target.closest('#loadDbQuestions')) { await loadQuestionsFromDatabase(); render(); return }
  if (e.target.closest('#syncLocalQuestions')) { await syncLocalQuestionsToDatabase(); return }
  if (e.target.closest('#startSmartContest')) { await startSmartContest(); return }
  if (e.target.closest('#endSmartContest')) { endSmartContest(); return }
  if (e.target.closest('#resetSmartContest')) { resetSmartContest(); return }
  if (e.target.closest('#playClap')) { playClap(); return }
  if (e.target.closest('#startSolo')) { await startSolo('Solo Practice'); return }
  if (e.target.closest('#startBotBattle')) { await startBattle('Bot'); return }
  if (e.target.closest('#startBattle') || e.target.closest('#startBattle2')) { await startBattle(); return }
})

document.addEventListener('change', e => {
  if (e.target.id === 'dobInput') document.getElementById('ageOutput').value = ageFromDob(e.target.value)
  if (e.target.id === 'smartClass') { state.smart.classLevel = e.target.value; state.smart.topic = topicOptionsFor(e.target.value)[0] || ''; state.smart.topicArea = inferTopicArea(state.smart.topic); render() }
  if (e.target.id === 'smartTopic') { state.smart.topic = e.target.value; state.smart.topicArea = inferTopicArea(e.target.value); render() }
  if (e.target.id === 'battleClass') { state.battle.classLevel = e.target.value; state.battle.topic = topicOptionsFor(e.target.value)[0] || ''; state.battle.topicArea = inferTopicArea(state.battle.topic); render() }
  if (e.target.id === 'battleTopic') { state.battle.topic = e.target.value; state.battle.topicArea = inferTopicArea(e.target.value); render() }
  if (e.target.id === 'soloClass') { state.solo.classLevel = e.target.value; state.solo.topic = topicOptionsFor(e.target.value)[0] || ''; render() }
  if (e.target.id === 'soloTopic') { state.solo.topic = e.target.value; state.solo.topicArea = inferTopicArea(e.target.value); render() }
  if (e.target.id === 'adminLevel' || e.target.id === 'adminTopic' || e.target.id === 'manualLevel' || e.target.id === 'manualTopic') { render() }
})
document.addEventListener('submit', async e => { e.preventDefault(); if (e.target.id === 'signupForm') await signup(e.target); if (e.target.id === 'loginForm') await login(e.target); if (e.target.id === 'adminQuestionForm') await saveQuestion(e.target); if (e.target.id === 'aiGenerateForm') await aiGenerate(e.target) })

render()
